function solve(n: number, edges: number[][], label: string): number {
    const graph: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    let maxLen = 1;

    for (let start = 0; start < n; start++) {
        const stack: [number, number, string][] = [[start, 1 << start, label[start]]];
        while (stack.length > 0) {
            const [node, mask, currentStr] = stack.pop()!;
            for (const neighbor of graph[node]) {
                if (!(mask & (1 << neighbor))) {
                    const newMask = mask | (1 << neighbor);
                    const newStr = currentStr + label[neighbor];
                    if (newStr === newStr.split('').reverse().join('')) {
                        maxLen = Math.max(maxLen, newStr.length);
                    }
                    stack.push([neighbor, newMask, newStr]);
                }
            }
        }
    }

    return maxLen;
}
